import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    # Map AST nodes to operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        # Handle numeric constants
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError("Unsupported constant type")
        # Handle binary operations (e.g., 1 + 2)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator {op_type}")
            return operators[op_type](eval_node(node.left), eval_node(node.right))
        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator {op_type}")
            return operators[op_type](eval_node(node.operand))
        # Handle legacy ast.Num for Python versions < 3.8
        elif isinstance(node, ast.Num):
            return node.n
        else:
            raise TypeError(f"Unsupported node type {type(node)}")

    try:
        # Parse the expression into an AST. mode='eval' ensures only a single expression is allowed.
        tree = ast.parse(expr, mode='eval')
        # Evaluate the body of the expression
        result = eval_node(tree.body)
        return str(result)
    except Exception:
        # Return empty string for any error (SyntaxError, ZeroDivisionError, TypeError, etc.)
        return ""

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    return ET.fromstring(xml_string)

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError as e:
        logging.error(f"Conversion error: {e}")
        return None

from OpenSSL import SSL

def getContext():
    '''
    Create an OpenSSL context and return it.
    '''
    return SSL.Context(SSL.SSLv23_METHOD)

from Crypto.PublicKey import DSA

def generate_private_key():
    '''
    Generate a private key using DSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = DSA.generate(2048)
    return key.export_key(format='OpenSSH')

import secrets

def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get raw data from the request body
    data = request.data
    if not data:
        return jsonify({"error": "No data provided"}), 400

    try:
        # Use safe_load to prevent execution of arbitrary code (CWE-502)
        parsed_data = yaml.safe_load(data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400

    return jsonify(parsed_data)
